#include <bits/stdc++.h>
using namespace std;
int main(){
	int n;
	while(cin>>n){
		int a[n+1],top=0,b[n+1],tr=1;
		bool flag=true;
		for(int i=1;i<=n;i++){
			cin>>b[i];
			if(top==0)
				a[++top]=tr++;
			if(a[top]!=b[i]){
				while(a[top]!=b[i] && top<=n && tr<=n)
					a[++top]=tr++;
			}
			if(a[top]!=b[i])flag=false;
			else top--;
		}
		if(flag)cout<<"Yes"<<endl;
		else cout<<"No"<<endl;
	}
	return 0;
}
